/* VCD dumping functions */
MOD_mkXsimTop & mkXsimTop_backing(tSimStateHdl simHdl)
{
  static MOD_mkXsimTop *instance = NULL;
  if (instance == NULL)
  {
    vcd_set_backing_instance(simHdl, true);
    instance = new MOD_mkXsimTop(simHdl, "top", NULL);
    vcd_set_backing_instance(simHdl, false);
  }
  return *instance;
}
void MODEL_mkXsimTop::dump_VCD_defs()
{
  (mkXsimTop_instance->dump_VCD_defs)(vcd_depth(sim_hdl));
}
void MODEL_mkXsimTop::dump_VCD(tVCDDumpType dt)
{
  (mkXsimTop_instance->dump_VCD)(dt, vcd_depth(sim_hdl), mkXsimTop_backing(sim_hdl));
}
